/**
 * @brief Solves the problem by iterating through all possible subsets of nums.
 * 
 * Since the constraint on the size of nums is small (up to 40), 
 * iterating through all $2^{40}$ subsets is too slow.
 * However, the problem statement's constraints might imply a meet-in-the-middle
 * or a dynamic programming approach if the numbers were smaller, but here
 * $N \le 40$ suggests $O(2^{N/2})$ might pass.
 * 
 * Given the constraints $N \le 40$, $O(2^N)$ is too slow. $O(2^{N/2})$ is feasible.
 * We will use Meet-in-the-Middle (MiTM).
 */
class Solution {
private:
    // Function to generate all subset XOR sums and the minimum number of elements 
    // required to achieve that XOR sum.
    // map: XOR_sum -> minimum_size_of_subset_to_achieve_it
    void generate_sums(const vector<Int64>& arr, int start, int end, vector<pair<Int64, int>>& sums_list) {
        int n = end - start;
        int total_subsets = 1 << n;

        for (int i = 0; i < total_subsets; ++i) {
            Int64 current_xor_sum = 0;
            int count = 0;
            for (int j = 0; j < n; ++j) {
                if ((i >> j) & 1) {
                    current_xor_sum ^= arr[start + j];
                    count++;
                }
            }
            // Store (XOR_sum, number_of_elements_kept)
            sums_list.push_back({current_xor_sum, count});
        }
    }

public:
    Int64 solve(vector<Int64>& nums, Int64 target) {
        int N = nums.size();
        if (N == 0) {
            return (target == 0) ? 0 : -1;
        }

        int N1 = N / 2;
        int N2 = N - N1;

        vector<pair<Int64, int>> sums1;
        vector<pair<Int64, int>> sums2;

        // Generate sums for the first half [0, N1-1]
        generate_sums(nums, 0, N1, sums1);

        // Generate sums for the second half [N1, N-1]
        generate_sums(nums, N1, N, sums2);

        // Optimization: For each sum, we only care about the smallest subset size 
        // that achieves it.

        // Map 1: XOR_sum -> min_size_kept
        vector<pair<Int64, int>> map1_filtered;
        // Sort to handle duplicates and find minimum size easily
        sort(sums1.begin(), sums1.end());

        if (!sums1.empty()) {
            map1_filtered.push_back(sums1[0]);
            for (size_t i = 1; i < sums1.size(); ++i) {
                if (sums1[i].first == sums1[i-1].first) {
                    // Keep the one with minimum size
                    if (sums1[i].second < map1_filtered.back().second) {
                        map1_filtered.back().second = sums1[i].second;
                    }
                } else {
                    map1_filtered.push_back(sums1[i]);
                }
            }
        }

        // Map 2: XOR_sum -> min_size_kept
        vector<pair<Int64, int>> map2_filtered;
        sort(sums2.begin(), sums2.end());

        if (!sums2.empty()) {
            map2_filtered.push_back(sums2[0]);
            for (size_t i = 1; i < sums2.size(); ++i) {
                if (sums2[i].first == sums2[i-1].first) {
                    // Keep the one with minimum size
                    if (sums2[i].second < map2_filtered.back().second) {
                        map2_filtered.back().second = sums2[i].second;
                    }
                } else {
                    map2_filtered.push_back(sums2[i]);
                }
            }
        }


        // Now, iterate through all pairs (s1, s2) such that s1 ^ s2 = target
        // This means s2 = target ^ s1

        int min_removed = N + 1;
        bool found = false;

        // Iterate over map1_filtered
        for (const auto& p1 : map1_filtered) {
            Int64 s1 = p1.first;
            int k1 = p1.second; // k1 is the number of elements KEPT in the first half

            Int64 required_s2 = target ^ s1;

            // Search for required_s2 in map2_filtered using binary search (std::lower_bound)
            // We need to find the pair in map2_filtered whose first element is required_s2.

            // Create a dummy pair for lower_bound search
            pair<Int64, int> search_key = {required_s2, 0}; 

            auto it = lower_bound(map2_filtered.begin(), map2_filtered.end(), search_key, 
                [](const pair<Int64, int>& a, const pair<Int64, int>& b) {
                    return a.first < b.first;
                });

            if (it != map2_filtered.end() && it->first == required_s2) {
                int k2 = it->second; // k2 is the number of elements KEPT in the second half

                // Total kept elements = k1 + k2
                int total_kept = k1 + k2;
                // Total removed elements = N - total_kept
                int total_removed = N - total_kept;

                min_removed = min(min_removed, total_removed);
                found = true;
            }
        }

        if (!found) {
            return -1;
        }
        return (Int64)min_removed;
    }
};
